    if isinstance(date_str, str):
        try:
            dt = datetime.fromisoformat(date_str.replace('Z', '+00:00'))
            return dt.strftime('%B %d, %Y')
        except (ValueError, TypeError):
            return date_str
    return date_str


@app.template_filter('format_datetime')
