def test_scraper_entrypoints_registry_covers_all_scrapers():
    """SCRAPER_ENTRYPOINTS should map every module used in main()."""
    import scrape_all

    for module_name, _desc in scrape_all.main.__code__.co_consts:
        if isinstance(module_name, str) and module_name.startswith("scrape_"):
            assert module_name in scrape_all.SCRAPER_ENTRYPOINTS
