@app.route('/tool/<int:tool_id>')
def tool_detail(tool_id):
    """Show detailed view of a specific tool"""
    tool = get_startup_by_id(tool_id)
    if not tool:
        logger.warning(
            "render.tool_missing",
            extra={"event": "render.tool_missing", "tool_id": tool_id},
        )
